import { describe, it, expect } from "vitest";
import { nextGeneration, type Cell } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty array for empty grid");
  it.todo("should return empty array for single live cell (dies of underpopulation)");
  it.todo("should return empty array when all cells die of underpopulation");
  it.todo("should keep cells alive when they have exactly 2 live neighbors (survival)");
  it.todo("should keep cells alive when they have exactly 3 live neighbors (survival)");
  it.todo("should kill live cell with more than 3 live neighbors (overpopulation)");
  it.todo("should bring dead cell to life with exactly 3 live neighbors (reproduction)");
  it.todo("should keep block (2x2) pattern unchanged as a still life");
  it.todo("should evolve blinker from vertical to horizontal in one generation");
});
